let allData = {{workflowparams:allData}}
const updatedSM = []
const saveAs = {{workflowparams:saveAs}}

if (saveAs === "Cancelled") {
  const rawData = {{node:get_node_ulAJ3pZj.data.data}}
  allData = Array.isArray(rawData) ? rawData[0] : rawData
}

for (const [index, smLineItem] of allData.stock_movement.entries()) {
  smLineItem.organization_id = allData.organization_id;
  smLineItem.line_index = index + 1;

  updatedSM.push(smLineItem)
}

allData.stock_movement = updatedSM

if ({{workflowparams:pageStatus}} === "Add") {
  allData.stock_movement_status = "Draft"
}

if (saveAs === "Draft") {
  if(allData.stock_movement_no_type !== -9999 && (
  !allData.stock_movement_no || allData.stock_movement_no === null || allData.stock_movement_no === ''
)) {
  allData.stock_movement_no = 'draft'
  }
} else {
  if (
  allData.stock_movement_no_type !== -9999 &&
  (!allData.stock_movement_no ||
    allData.stock_movement_no === null ||
    allData.stock_movement_no === "" ||
    allData.stock_movement_status !== "Created")
) {
  allData.stock_movement_no = 'issued'
  }
}

return {
  allData: allData,
  stock_movement_status: allData.stock_movement_status,
}

return {
  required_fields: JSON.stringify([
  { name: "stock_movement_no", label: "Stock Movement No" },
  { name: "movement_type", label: "Movement Type" },
  { name: "issue_date", label: "Issue Date" },
  { name: "issuing_operation_faci", label: "Issuing Plant" },
  { name: "receiving_operation_faci", label: "Receiving Plant" },
  {
    name: "stock_movement",
    label: "Item Information",
    isArray: true,
    arrayType: "object",
    arrayFields: [],
  },
]),
  data: JSON.stringify({
    stock_movement_no: {{node:code_node_37LA0tgq.data.allData.stock_movement_no}},
    movement_type: {{node:code_node_37LA0tgq.data.allData.movement_type}},
    issue_date: {{node:code_node_37LA0tgq.data.allData.issue_date}},
    issuing_operation_faci: {{node:code_node_37LA0tgq.data.allData.issuing_operation_faci}},
    receiving_operation_faci: {{node:code_node_37LA0tgq.data.allData.receiving_operation_faci}},
    stock_movement: {{node:code_node_37LA0tgq.data.allData.stock_movement}}
  })
}

const allData = {{node:code_node_37LA0tgq.data.allData}}
const subformData = allData.stock_movement || []

let quantityFailed = 0
let quantityMessage

// Prefer temp_qty_data per line; fall back to balance_index if nothing on lines
let anyQty = false;
for (const smRow of subformData) {
  let parsed = [];
  try {
    parsed = JSON.parse(smRow.temp_qty_data || "[]");
  } catch (e) {
    parsed = [];
  }
  if (Array.isArray(parsed) && parsed.some((b) => parseFloat(b.sm_quantity || 0) > 0)) {
    anyQty = true;
    break;
  }
}

if (!anyQty) {
  const fallback = (allData.balance_index || []).some(
    (b) => parseFloat(b.sm_quantity || 0) > 0
  );
  anyQty = fallback;
}

if (!anyQty) {
  quantityFailed = 1
  quantityMessage = 'No quantity selected to transfer'
}

return {
  quantityFailed: quantityFailed,
  quantityMessage: quantityMessage
};

const page_status = {{workflowparams:pageStatus}};
const allData = {{node:code_node_37LA0tgq.data.allData}}

const subformData = allData.stock_movement;
const currentIndexRaw = {{node:get_cache_node_ICyUff2y.data}};
const index = currentIndexRaw ? parseInt(currentIndexRaw, 10) : 0;

const plant_id = allData.issuing_operation_faci;
const receiving_plant = allData.receiving_operation_faci;
const receiving_default_location_id = {{node:get_node_WtFOLdKB.data.data.id}};
const receiving_default_storage_location_id = {{node:get_node_WtFOLdKB.data.data.storage_location_id}};
const organization_id = allData.organization_id;
const stock_movement_no = allData.stock_movement_no;
const doc_date = allData.issue_date;

const item = subformData[index];
const material_id = item.item_selection;
const material_uom = item.quantity_uom || item.received_quantity_uom;
const total_quantity = item.total_quantity;
const location_id = item.location_id;
const batch_id = item.batch_id || null;
const inventory_category = "Unrestricted";

// Prefer temp_qty_data per line; fall back to balance_index entries scoped to this row
let tempDataParsed = [];
try {
  tempDataParsed = JSON.parse(item.temp_qty_data || "[]");
} catch (e) {
  tempDataParsed = [];
}
if (!Array.isArray(tempDataParsed)) tempDataParsed = [];

let balancesToProcess = tempDataParsed.filter(
