);

if (balancesToProcess.length === 0) {
  balancesToProcess = (allData.balance_index || []).filter(
    (b) =>
      String(b.row_index) === String(index) &&
      b.sm_quantity &&
      parseFloat(b.sm_quantity) > 0
  );
}

return {
