const allData = {{node:code_node_37LA0tgq.data.allData}};
const stockMovement = allData.stock_movement || [];
const balanceIndex = allData.balance_index || [];
const organizationId = allData.organization_id;
const sourcePlantId = allData.issuing_operation_faci;

// Branch A reversal: each unique source HU goes back to issuing plant + its source bin
const huMovesMap = new Map();
for (const [idx, smRow] of stockMovement.entries()) {
  // Prefer temp_qty_data per line; fall back to balance_index entries for this row
  let entries = [];
  try {
    entries = JSON.parse(smRow.temp_qty_data || "[]");
  } catch (e) {
    entries = [];
  }
  if (!Array.isArray(entries) || entries.length === 0) {
    entries = balanceIndex.filter(
      (b) => String(b.row_index) === String(idx)
    );
  }

  for (const entry of entries) {
    const huId = entry.handling_unit_id;
    if (!huId) continue;
    if (huMovesMap.has(huId)) continue;
    huMovesMap.set(huId, {
      handling_unit_id: huId,
      plant_id: sourcePlantId,
      organization_id: organizationId,
      location_id: entry.location_id,
      storage_location_id: entry.storage_location_id || "",
    });
  }
}

const huMoves = Array.from(huMovesMap.values());
return { huMoves: huMoves, huMovesLength: huMoves.length };

const u = {{node:loop_aKvWTpyi}};
return {
