};

const allData = {{node:code_node_37LA0tgq.data.allData}};
const stockMovement = allData.stock_movement || [];
const balanceIndex = allData.balance_index || [];
const organizationId = allData.organization_id;
const receivingPlantId = allData.receiving_operation_faci;
const receivingDefaultLoc = {{node:get_node_WtFOLdKB.data.data.id}};
const receivingDefaultStorage = {{node:get_node_WtFOLdKB.data.data.storage_location_id}};

let husAtReceiving = {{node:search_node_JXM2g1CY.data.data}} || [];
if (!Array.isArray(husAtReceiving)) husAtReceiving = [husAtReceiving];

// Find new HU via transfer_source_hu_id linkage
const huBySource = new Map(husAtReceiving.map((h) => [h.transfer_source_hu_id, h]));

// Empty the new HU at receiving plant default bin
const unloadMap = new Map();
for (const [idx, smRow] of stockMovement.entries()) {
  // Prefer temp_qty_data per line; fall back to balance_index entries for this row
  let entries = [];
  try {
    entries = JSON.parse(smRow.temp_qty_data || "[]");
  } catch (e) {
    entries = [];
  }
  if (!Array.isArray(entries) || entries.length === 0) {
    entries = balanceIndex.filter(
      (b) => String(b.row_index) === String(idx)
    );
  }

  const lineUom = (smRow && (smRow.received_quantity_uom || smRow.quantity_uom)) || "";

  for (const entry of entries) {
    const sourceHuId = entry.handling_unit_id;
    if (!sourceHuId) continue;
    const qty = parseFloat(entry.sm_quantity || 0);
    if (qty <= 0) continue;

    const newHu = huBySource.get(sourceHuId);
    if (!newHu) continue;  // defensive — new HU not at default; skip

    if (!unloadMap.has(newHu.id)) {
      unloadMap.set(newHu.id, {
        handling_unit_id: newHu.id,
        plant_id: receivingPlantId,
        organization_id: organizationId,
        location_id: receivingDefaultLoc,
        storage_location_id: receivingDefaultStorage,
        items: [],
      });
    }
    unloadMap.get(newHu.id).items.push({
      material_id: entry.material_id,
      material_uom: entry.material_uom || lineUom,
      balance_id: "",
      batch_id: entry.batch_id || "",
      quantity: qty,
    });
  }
}

const huUnloads = Array.from(unloadMap.values()).map((u) => ({
  handling_unit_id: u.handling_unit_id,
  plant_id: u.plant_id,
  organization_id: u.organization_id,
  location_id: u.location_id,
  storage_location_id: u.storage_location_id,
  table_hu_items: u.items,
}));

return { huUnloads: huUnloads, huUnloadsLength: huUnloads.length };

const u = {{node:loop_J2OEHMwA}};
return {
