  }
  if (!Array.isArray(entries) || entries.length === 0) {
    entries = balanceIndex.filter(
      (b) => String(b.row_index) === String(idx)
    );
  }

  const lineUom = (smRow && (smRow.received_quantity_uom || smRow.quantity_uom)) || "";

  for (const entry of entries) {
    const sourceHuId = entry.handling_unit_id;
    if (!sourceHuId) continue;
    const qty = parseFloat(entry.sm_quantity || 0);
    if (qty <= 0) continue;

    if (!reloadMap.has(sourceHuId)) {
      reloadMap.set(sourceHuId, {
        handling_unit_id: sourceHuId,
        plant_id: sourcePlantId,
        organization_id: organizationId,
        location_id: entry.location_id,
        storage_location_id: entry.storage_location_id || "",
        items: [],
      });
    }
    reloadMap.get(sourceHuId).items.push({
      material_id: entry.material_id,
      material_uom: entry.material_uom || lineUom,
      balance_id: entry.balance_id || "",
      batch_id: entry.batch_id || "",
      quantity: qty,
      location_id: entry.location_id,
    });
  }
}

const huLoads = Array.from(reloadMap.values()).map((u) => ({
  handling_unit_id: u.handling_unit_id,
  plant_id: u.plant_id,
  organization_id: u.organization_id,
  location_id: u.location_id,
  storage_location_id: u.storage_location_id,
  table_hu_items: u.items,
}));

return { huLoads: huLoads, huLoadsLength: huLoads.length };

