const initialBalanceIndex = {{node:get_node_1wi90Edk.data.data.balance_index}}
const currentBalanceIndex = {{node:code_node_37LA0tgq.data.allData.balance_index}}
const status = {{node:code_node_37LA0tgq.data.stock_movement_status}}

let isDifferent = 0

if (status === "Issued") {
  if (initialBalanceIndex.length !== currentBalanceIndex.length) {
    isDifferent = 1;
  } else {
    for (let i = 0; i < initialBalanceIndex.length; i++) {
      if (
        initialBalanceIndex[i].sm_quantity !==
        currentBalanceIndex[i].sm_quantity
      ) {
        isDifferent = 1;
        break;
      }
    }
  }
}

return {
  isDifferent: isDifferent
}

const allData = {{node:code_node_37LA0tgq.data.allData}}

const initialMovementTable = {{node:get_node_1wi90Edk.data.data.stock_movement}}
const initialBalanceIndex = {{node:get_node_1wi90Edk.data.data.balance_index}}

const currentMovementTable = {{node:code_node_37LA0tgq.data.allData.stock_movement}}
const currentBalanceIndex = {{node:code_node_37LA0tgq.data.allData.balance_index}}

const plant_id = allData.issuing_operation_faci;
const receiving_plant = allData.receiving_operation_faci;
const receiving_default_location_id = {{node:get_node_WtFOLdKB.data.data.id}};
const receiving_default_storage_location_id = {{node:get_node_WtFOLdKB.data.data.storage_location_id}};
const organization_id = allData.organization_id;
const stock_movement_no = allData.stock_movement_no;
const page_status = {{workflowparams:pageStatus}}
const doc_date = allData.issue_date;

const balanceToAdd = []
const balanceToSubtract = []

// Create key using material_id + location_id + batch_id + category
const createKey = (item) => {
  const batchId = item.batch_id || ""
  const category = item.category || "Unrestricted"
  const huId = item.handling_unit_id || ""
  return `${item.material_id}|${item.location_id}|${batchId}|${category}|${huId}`
}

// Build map of initial quantities from balance_index
const initialMap = {}
for (const item of initialBalanceIndex) {
  if (parseFloat(item.sm_quantity || 0) > 0) {
    const key = createKey(item)
    initialMap[key] = {
      material_id: item.material_id,
      material_uom: item.material_uom,
      location_id: item.location_id,
      batch_id: item.batch_id || null,
      category: item.category || "Unrestricted",
      sm_quantity: parseFloat(item.sm_quantity || 0),
      manufacturing_date: item.manufacturing_date || null,
      expired_date: item.expired_date || null,
      handling_unit_id: item.handling_unit_id || null
    }
  }
}

// Build map of current quantities from balance_index
const currentMap = {}
for (const item of currentBalanceIndex) {
  if (parseFloat(item.sm_quantity || 0) > 0) {
    const key = createKey(item)
    currentMap[key] = {
      material_id: item.material_id,
      material_uom: item.material_uom,
      location_id: item.location_id,
      batch_id: item.batch_id || null,
      category: item.category || "Unrestricted",
      sm_quantity: parseFloat(item.sm_quantity || 0),
      manufacturing_date: item.manufacturing_date || null,
      expired_date: item.expired_date || null,
      handling_unit_id: item.handling_unit_id || null
    }
  }
}

// Compare and calculate differences
// Check items in current (new or increased)
for (const key in currentMap) {
  const currentItem = currentMap[key]
  const initialItem = initialMap[key]

  if (!initialItem) {
    // New item added (or category changed - treated as new)
    balanceToAdd.push({
      material_id: currentItem.material_id,
      material_uom: currentItem.material_uom,
      location_id: currentItem.location_id,
      batch_id: currentItem.batch_id,
      category: currentItem.category,
      sm_quantity: currentItem.sm_quantity,
      manufacturing_date: currentItem.manufacturing_date,
      expired_date: currentItem.expired_date
    })
  } else {
    const diff = currentItem.sm_quantity - initialItem.sm_quantity
    if (diff > 0) {
      // Quantity increased
      balanceToAdd.push({
        material_id: currentItem.material_id,
        material_uom: currentItem.material_uom,
        location_id: currentItem.location_id,
        batch_id: currentItem.batch_id,
        category: currentItem.category,
        sm_quantity: diff,
        manufacturing_date: currentItem.manufacturing_date,
        expired_date: currentItem.expired_date,
        handling_unit_id: currentItem.handling_unit_id
      })
    } else if (diff < 0) {
      // Quantity decreased
      balanceToSubtract.push({
        material_id: currentItem.material_id,
        material_uom: currentItem.material_uom,
        location_id: currentItem.location_id,
        batch_id: currentItem.batch_id,
        category: currentItem.category,
        sm_quantity: Math.abs(diff),
        manufacturing_date: currentItem.manufacturing_date,
        expired_date: currentItem.expired_date,
        handling_unit_id: currentItem.handling_unit_id
      })
    }
  }
}

// Check items removed (in initial but not in current, or category changed)
for (const key in initialMap) {
  if (!currentMap[key]) {
    const initialItem = initialMap[key]
    balanceToSubtract.push({
      material_id: initialItem.material_id,
      material_uom: initialItem.material_uom,
      location_id: initialItem.location_id,
      batch_id: initialItem.batch_id,
      category: initialItem.category,
      sm_quantity: initialItem.sm_quantity,
      manufacturing_date: initialItem.manufacturing_date,
      expired_date: initialItem.expired_date,
      handling_unit_id: initialItem.handling_unit_id
    })
  }
}

return {
  plant_id: plant_id,
  receiving_plant: receiving_plant,
  receiving_default_location_id: receiving_default_location_id,
  receiving_default_storage_location_id: receiving_default_storage_location_id,
  organization_id: organization_id,
  stock_movement_no: stock_movement_no,
  page_status: page_status,
  doc_date: doc_date,
  balanceToAdd: balanceToAdd,
  balanceToAddLength: balanceToAdd.length,
  balanceToSubtract: balanceToSubtract,
  balanceToSubtractLength: balanceToSubtract.length
}

